// Parse ports and carriers from form input
const formData = $input.first().json;
const portsText = (formData.origin_ports || '').trim();
const carriersText = (formData.carriers || '').trim();
const freightMode = (formData.freight_mode || 'Sea Freight').trim();
const riskQuestion = (formData.risk_question || '').trim();

function normalizeUrl(raw) {
  if (!raw) return '';
  let u = raw.trim().replace(/[),.;]+$/, '');
  if (!/^https?:\/\//i.test(u)) u = 'https://' + u;
  const hostish = u.replace(/^https?:\/\//i, '');
  if (!hostish.includes('.')) return '';
  return u;
}

function splitNameAndUrl(line) {
  const clean = line.replace(/^\s*[-*•]\s*/, '').trim();
  if (clean.includes('—')) {
    const [name, ...rest] = clean.split('—');
    return { name: name.trim(), url: rest.join('—').trim() };
  }
  if (clean.includes(' - ')) {
    const [name, ...rest] = clean.split(' - ');
    return { name: name.trim(), url: rest.join(' - ').trim() };
  }
  const m = clean.match(/\b((?:https?:\/\/)?(?:www\.)?[a-z0-9.-]+\.[a-z]{2,}(?:\/\S*)?)\b/i);
  if (m) {
    const rawUrl = m[1];
    const name = clean.replace(rawUrl, '').replace(/[-—\s]+$/, '').trim();
    return { name: name.trim(), url: rawUrl.trim() };
  }
  return { name: clean, url: '' };
}

const portLines = portsText.split(/\r?\n/).map(s => s.trim()).filter(Boolean);
const carrierLines = carriersText.split(/\r?\n/).map(s => s.trim()).filter(Boolean);

const ports = portLines.map((line, i) => {
  const { name, url } = splitNameAndUrl(line);
  return { id: `port-${i + 1}`, name, url: normalizeUrl(url), type: 'port', freightMode, riskQuestion };
});

const carriers = carrierLines.map((line, i) => {
  const { name, url } = splitNameAndUrl(line);
  return { id: `carrier-${i + 1}`, name, url: normalizeUrl(url), type: 'carrier', freightMode, riskQuestion };
});

const allTargets = [...ports, ...carriers];
return allTargets.map(t => ({ json: t }));

// Build a consolidated target list for GPT planning
const items = $input.all();
let portList = '';
let carrierList = '';
let riskQuestion = '';
let freightMode = '';

for (let i = 0; i < items.length; i++) {
  const item = items[i].json;
  if (i === 0) { riskQuestion = item.riskQuestion; freightMode = item.freightMode; }
  if (item.type === 'port') portList += `- ${item.name} (${item.url})\n`;
  if (item.type === 'carrier') carrierList += `- ${item.name} (${item.url})\n`;
}

return { json: { portList: portList.trim(), carrierList: carrierList.trim(), riskQuestion, freightMode } };

// Parse GPT goals for logistics targets
const j = $input.first().json;

const text =
  j?.output?.[0]?.content?.find(c => c?.type === 'output_text')?.text
  ?? j?.output?.[0]?.content?.[0]?.text
  ?? null;

if (!text || typeof text !== 'string') {
  return [{ json: { error: 'No output_text found', sample: j } }];
}

let parsed;
try { parsed = JSON.parse(text); }
catch (e) {
  const stripped = text.replace(/```json\s*|```/g, '').trim();
  parsed = JSON.parse(stripped);
}

const goals = Array.isArray(parsed?.goals) ? parsed.goals : [];

return goals.map(g => ({
  json: {
    target_name: g.target_name || '',
    target_type: g.target_type || 'unknown',
    target_url: g.target_url || '',
    goal: g.goal || ''
  }
}));

// Prepare TinyFish run parameters for each logistics target
const item = $input.item.json;

let runUrl = item.target_url || item.url || '';
if (runUrl && !runUrl.startsWith('http://') && !runUrl.startsWith('https://')) {
  runUrl = 'https://' + runUrl;
}

let runGoal = '';
if (item.goal) {
  runGoal = item.goal;
} else {
  const riskQuestion = item.riskQuestion || 'identify any operational risks or alerts';
  const name = item.name || item.target_name || 'this logistics target';
  const type = item.type || item.target_type || 'target';
  if (type === 'port') {
    runGoal = `Visit ${name} website and extract: (1) current congestion alerts or notices, (2) vessel wait times or berth availability, (3) gate hours and any closures, (4) any severe weather or operational disruptions. Relevant to: ${riskQuestion}`;
  } else {
    runGoal = `Visit ${name} website and extract: (1) active service advisories or suspensions, (2) route disruptions or delays, (3) booking surcharges or capacity alerts, (4) any weather or geopolitical risk notices. Relevant to: ${riskQuestion}`;
  }
}

runGoal += '\n\nWhen you find evidence, list the exact source URLs (including child pages visited) in a "sources" section, and provide a risk level assessment: LOW, MEDIUM, HIGH, or CRITICAL based on what you found.';

return {
  json: {
    id: item.id,
    name: item.name || item.target_name,
    type: item.type || item.target_type,
    url: item.url,
    runUrl,
    runGoal,
    riskQuestion: item.riskQuestion,
    freightMode: item.freightMode
  }
};

// Evaluate all logistics scouting runs
const items = $input.all().map(i => i.json);

let runs = [];
for (const x of items) {
  if (Array.isArray(x)) runs.push(...x);
  else if (Array.isArray(x?.data)) runs.push(...x.data);
  else if (Array.isArray(x?.runs)) runs.push(...x.runs);
  else if (x && (x.run_id || x.status)) runs.push(x);
}

const seen = new Set();
runs = runs.filter(r => {
  const id = r?.run_id ?? r?.runId ?? JSON.stringify(r);
  if (seen.has(id)) return false;
  seen.add(id);
  return true;
});

const terminal = new Set(["COMPLETED", "FAILED", "CANCELLED"]);
const allDone = runs.length > 0 && runs.every(r => terminal.has(String(r.status || '').toUpperCase()));

return [{ json: { raw: items, runs, allDone } }];

// Rehydrate run IDs for next poll iteration
const inItem = $input.first().json;
const arr = Array.isArray(inItem.runs) ? inItem.runs : (Array.isArray(inItem.raw) ? inItem.raw : []);
const runIds = arr.map(r => r?.run_id || r?.runId).filter(Boolean);
const ctx = { riskQuestion: inItem.riskQuestion, freightMode: inItem.freightMode };

return runIds.map(runId => ({ json: { ...ctx, runId, run_id: runId } }));

// Normalize TinyFish runs and extract logistics intelligence signals
const inItems = $input.all().map(i => i.json);

// Pull all target context from upstream
const compItems = $("Match Targets with Goals")?.all?.() ?? [];
const targets = compItems.map((it) => {
  const j = it.json ?? {};
  return {
    id: j.id ?? null,
    name: j.name ?? j.target_name ?? '',
    type: j.type ?? j.target_type ?? 'unknown',
    url: j.url ?? '',
    runUrl: j.runUrl ?? j.target_url ?? j.url ?? '',
    runGoal: j.runGoal ?? j.goal ?? '',
    riskQuestion: j.riskQuestion ?? '',
    freightMode: j.freightMode ?? ''
  };
}).filter(t => t.name);

const riskQuestion = targets.find(t => t.riskQuestion)?.riskQuestion ?? '';
const freightMode = targets.find(t => t.freightMode)?.freightMode ?? '';

// Flatten runs from input
let runsRaw = [];
for (const x of inItems) {
  if (Array.isArray(x)) runsRaw.push(...x);
  else if (Array.isArray(x?.data)) runsRaw.push(...x.data);
  else if (Array.isArray(x?.runs)) runsRaw.push(...x.runs);
  else if (x?.run_id || x?.status) runsRaw.push(x);
}

const runs = runsRaw.map((run) => {
  const status = String(run.status ?? '').toUpperCase();
  const resultObj = run.result ?? null;
  const sources = Array.isArray(resultObj?.sources) ? resultObj.sources : Array.isArray(run.sources) ? run.sources : null;

  // Attempt to extract risk level from result text
  const resultText = resultObj ? JSON.stringify(resultObj) : '';
  let detectedRiskLevel = 'UNKNOWN';
  if (/CRITICAL/i.test(resultText)) detectedRiskLevel = 'CRITICAL';
  else if (/HIGH/i.test(resultText)) detectedRiskLevel = 'HIGH';
  else if (/MEDIUM/i.test(resultText)) detectedRiskLevel = 'MEDIUM';
  else if (/LOW/i.test(resultText)) detectedRiskLevel = 'LOW';

  return {
    run_id: run.run_id ?? null,
    status,
    goal: run.goal ?? '',
    created_at: run.created_at ?? null,
    finished_at: run.finished_at ?? null,
    error: run.error ?? null,
    sources,
    result: resultObj,
    detectedRiskLevel,
    rawResultText: resultObj ? JSON.stringify(resultObj, null, 2) : ''
  };
});

// Map runs by target name
const byName = {};
for (const t of targets) {
  byName[t.name] = {
    target: t,
    runs: runs.filter(r => (r.goal || '').toLowerCase().includes(t.name.toLowerCase()))
  };
}

return [{ json: { riskQuestion, freightMode, targets, runs, byName, allDone: runs.length > 0 && runs.every(r => ['COMPLETED','FAILED','CANCELLED'].includes(r.status)) } }];

// Build structured logistics intelligence payload
const root = $input.first().json;
const targets = Array.isArray(root.targets) ? root.targets : [];
const runs = Array.isArray(root.runs) ? root.runs : [];

// Compute overall risk level from all detected signals
const riskLevels = runs.map(r => r.detectedRiskLevel).filter(l => l !== 'UNKNOWN');
const riskPriority = { CRITICAL: 4, HIGH: 3, MEDIUM: 2, LOW: 1 };
const overallRisk = riskLevels.length > 0
  ? Object.keys(riskPriority).find(k => riskPriority[k] === Math.max(...riskLevels.map(l => riskPriority[l] || 0)))
  : 'UNKNOWN';

const payload = {
  riskQuestion: root.riskQuestion ?? '',
  freightMode: root.freightMode ?? '',
  overallRisk,
  targetCount: targets.length,
  runCount: runs.length,
  allDone: root.allDone ?? null,
  targets,
  runs,
  byName: root.byName ?? null
};

return [{
  json: {
    riskQuestion: payload.riskQuestion,
    freightMode: payload.freightMode,
    overallRisk,
    targets,
    runs,
    allDone: payload.allDone,
    targetCount: payload.targetCount,
    runCount: payload.runCount,
    intelligencePayloadText: JSON.stringify(payload, null, 2)
  }
}];

