// Extract the risk report text from OpenAI output
const j = $input.first().json;

const output = j.output ?? j.data?.output ?? null;
let textParts = [];

if (Array.isArray(output)) {
  for (const msg of output) {
    const content = msg?.content;
    if (Array.isArray(content)) {
      for (const c of content) {
        if (typeof c?.text === 'string' && c.text.trim()) textParts.push(c.text);
      }
    }
  }
}

if (textParts.length === 0) {
  const fallback = j.message?.content ?? j.message ?? j.text ?? j.output_text ?? '';
  if (typeof fallback === 'string' && fallback.trim()) textParts = [fallback];
}

const report = textParts.join('\n\n').trim();

return [{ json: { ...j, report, report_format: 'markdown' } }];

// Combine intelligence payload + report into final output
const items = $input.all().map(i => i.json);
const intelligence = items.find(x => Array.isArray(x.runs) || Array.isArray(x.targets)) || {};
const reportPart = items.find(x => typeof x.report === 'string') || {};

return [{
  json: {
    ...intelligence,
    report: reportPart.report || '',
    overallRisk: intelligence.overallRisk || 'UNKNOWN',
    generatedAt: new Date().toISOString()
  }
}];

// Generate Markdown intelligence report file
const j = $json;
const question = j.risk_question || '';
const freightMode = j.freight_mode || '';
const targets = j.target_names || '';
const overallRisk = j.overall_risk || 'UNKNOWN';
const report = j.report_md || '';
const createdAt = j.created_at || new Date().toISOString();

const riskEmoji = { CRITICAL: '🔴', HIGH: '🟠', MEDIUM: '🟡', LOW: '🟢', UNKNOWN: '⚪' };
const emoji = riskEmoji[overallRisk] || '⚪';

const safe = (question || 'logistics-report').replace(/[^a-z0-9-_ ]/gi, '').slice(0, 60).trim().replace(/\s+/g, '-');
const mdFilename = `logistics-intelligence-${safe || 'report'}-${Date.now()}.md`;

const mdContent = `# Logistics Intelligence Report ${emoji}

**Risk Question:** ${question}  
**Freight Mode:** ${freightMode}  
**Overall Risk Level:** ${overallRisk}  
**Monitored Targets:** ${targets}  
**Generated:** ${createdAt}  

---

${report}
`;

return [{ json: { mdFilename, mdContent } }];

const baseName = ($json.mdFilename || `logistics-report-${Date.now()}`).trim();
const filename = baseName.toLowerCase().endsWith('.md') ? baseName : `${baseName}.md`;
const md = $json.mdContent || '';

const binaryData = await this.helpers.prepareBinaryData(
  Buffer.from(md, 'utf8'),
  filename,
  'text/markdown'
);

return [{ json: { mdFilename: filename }, binary: { data: binaryData } }];

// Save complete intelligence payload as JSON
const data = $json;
const content = JSON.stringify(data, null, 2);
const filename = `logistics-intelligence-${Date.now()}.json`;

return [{
  json: data,
  binary: {
    data: await this.helpers.prepareBinaryData(
      Buffer.from(content, 'utf8'),
      filename,
      'application/json'
    )
  }
}];
